#!/bin/bash
IFS=. read -r a b c d <<< "$1"; m=$((0xffffffff << (32-$2))); n=$((((a<<24|b<<16|c<<8|d) & m))); printf "%d.%d.%d.%d - %d.%d.%d.%d\n" "$(( (n+1)>>24 & 255 ))" "$(( (n+1)>>16 & 255 ))" "$(( (n+1)>>8 & 255 ))" "$(( (n+1) & 255 ))" "$(( (n|(~m & 0xffffffff))-1>>24 & 255 ))" "$(( (n|(~m & 0xffffffff))-1>>16 & 255 ))" "$(( (n|(~m & 0xffffffff))-1>>8 & 255 ))" "$(( (n|(~m & 0xffffffff))-1 & 255 ))"
